import fs from 'fs';
import { google } from 'googleapis';
import { Agent, LocalAgentConfig } from '@google/antigravity';

// 1. Define JSON Schema
const ticketSchema = {
  type: 'object',
  properties: {
    category: { type: 'string' },
    priority_level: { type: 'string' },
    urgency_reason: { type: 'string' },
    assigned_team: { type: 'string' }
  },
  required: ['category', 'priority_level', 'urgency_reason', 'assigned_team']
};

async function runSheetsPipeline() {
  if (!fs.existsSync('token.json')) {
    console.error("token.json not found! Run Module 1 first.");
    return;
  }
  const tokenData = JSON.parse(fs.readFileSync('token.json', 'utf8'));
  const auth = google.auth.fromJSON(tokenData);
  const sheets = google.sheets({ version: 'v4', auth });

  // Create sheet
  console.log("Creating sheet...");
  const spreadsheet = await sheets.spreadsheets.create({
    requestBody: {
      properties: { title: 'AGY-311 Support Log' }
    }
  });
  const sheetId = spreadsheet.data.spreadsheetId;

  // Setup headers
  await sheets.spreadsheets.values.update({
    spreadsheetId: sheetId,
    range: 'Sheet1!A1:E2',
    valueInputOption: 'USER_ENTERED',
    requestBody: {
      values: [
        ['Ticket Description', 'Category', 'Priority', 'Reason', 'Assigned Team'],
        ['Database connection timed out when loading user profile page.', '', '', '', '']
      ]
    }
  });

  // Read ticket description
  const responseRange = await sheets.spreadsheets.values.get({
    spreadsheetId: sheetId,
    range: 'Sheet1!A2:A2'
  });
  const rawTicket = responseRange.data.values[0][0];

  // Execute Agent with JSON Schema
  console.log("Calling agent with schema...");
  const config = new LocalAgentConfig({
    systemInstruction: "Analyze support tickets. Categorize them and assign to Database, Frontend, Backend, or Security.",
    responseSchema: ticketSchema
  });
  const agent = new Agent(config);
  await agent.start();

  let structuredData;
  try {
    const response = await agent.chat(`Classify this ticket:\n${rawTicket}`);
    structuredData = await response.structured_output();
  } finally {
    await agent.stop();
  }

  // Update Sheet cells with structured data
  console.log("Updating analysis columns...");
  const analysisRow = [
    structuredData.category,
    structuredData.priority_level,
    structuredData.urgency_reason,
    structuredData.assigned_team
  ];

  await sheets.spreadsheets.values.update({
    spreadsheetId: sheetId,
    range: 'Sheet1!B2:E2',
    valueInputOption: 'USER_ENTERED',
    requestBody: {
      values: [analysisRow]
    }
  });
  console.log(`Spreadsheet complete! View at https://docs.google.com/spreadsheets/d/${sheetId}/edit`);
}

runSheetsPipeline().catch(console.error);
